package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.ContextKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import com.google.common.collect.Sets;

import java.util.Collection;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_BESTAANS_VERZEKERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_FIETS_VERGOEDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_OPZEG_VERGOEDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_WERKLOOSHEID_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_PREMIE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_ZIEKTE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.INHOUDINGEN_BEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.NETTO_KEY;

public class SommatiesAchterstal extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext mainContext) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            sommeerBedragen(mainContext, opdracht);
            sommeerBelastbaar(mainContext, opdracht);
            sommeerInhoudingen(mainContext, opdracht);
        }

        return CONTINUE_PROCESSING;
    }

    private static final ContextKey[] OPDRACHT_BEDRAG_KEYS =
            {BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_FIETS_VERGOEDING_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_OPZEG_VERGOEDING_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_ZIEKTE_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_PREMIE_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_BESTAANS_VERZEKERING_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_WERKLOOSHEID_KEY, NETTO_KEY};

    protected void sommeerBedragen(RekenContext context, Opdracht opdracht) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (ContextKey opdrachtBedragKey : OPDRACHT_BEDRAG_KEYS) {
            Money som = RekenTools.getSomProperty(opdrachtBedragKey, loonElementen);
            if (opdrachtBedragKey == BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY) {
                som = som.add(opdrachtContext.getMoney(opdrachtBedragKey));
            }
            opdrachtContext.put(opdrachtBedragKey, som);
        }
    }

    private static final Set<LnedefRegBv> SOMMATIE_REGIMES =
            Sets.immutableEnumSet(LnedefRegBv.VD_BV_10_BZ___TV, LnedefRegBv.VD_BV_10_OPZEG, LnedefRegBv.VD_BV_10_UKAG_NBV, LnedefRegBv.VD_BV_10_ABO__NBV,
                    LnedefRegBv.VD_BV_10_AWWV_NBV, LnedefRegBv.VD_BV_30_KOSTEN_NBV, LnedefRegBv.VD_BV_10_KWG__NBB, LnedefRegBv.VD_BV_30_BBI__TV,
                    LnedefRegBv.NBB_NFF, LnedefRegBv.VD_BV_10_FTSW_NBB, LnedefRegBv.VD_BV_10_MOB_VERG_NBB, LnedefRegBv.VD_BV_10_FTSW_EXC,
                    LnedefRegBv.VD_BV_50_VAC_TOE_NBB, LnedefRegBv.VD_BV_50_KOSTEN_NBB, LnedefRegBv.VD_BV_30_KOSTEN_TV);

    private void sommeerBelastbaar(RekenContext context, Opdracht opdracht) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (LnedefRegBv regime : SOMMATIE_REGIMES) {
            ContextKey key = new BelastbaarKey(regime);
            opdrachtContext.put(key, Money.ZERO);
        }
        for (LoonElement element : loonElementen) {
            LnedefRegBv regime = element.getRegimeBv();
            if (SOMMATIE_REGIMES.contains(regime)) {
                ContextKey key = new BelastbaarKey(regime);
                Money belastbaar = element.getPropertyMoney(BELASTBAAR_KEY);
                opdrachtContext.addToProperty(key, belastbaar);
            }
        }
    }

    private void sommeerInhoudingen(RekenContext mainContext, Opdracht opdracht) {
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
        Money totaalBedrag = Money.ZERO;
        Collection<LoonElement> elementen = manager.getOpdrachtsElementen(opdracht);
        for (LoonElement element : elementen) {
            if (element.getAardKodeExtensie().getAard().equals(AardKodeExt.I_KODE_EXT.getCode())) {
                totaalBedrag = totaalBedrag.add(element.getPropertyMoney(NETTO_KEY));
            }
        }
        opdrachtContext.put(INHOUDINGEN_BEDRAG_KEY, totaalBedrag);
    }

}
